     1→'use strict';
     2→
     3→/* ===== DOM refs ===== */
     4→const quickBtn      = document.getElementById('quick-btn');
     5→const quickRing     = document.getElementById('quick-ring');
     6→const brainstormBtn = document.getElementById('brainstorm-btn');
     7→const brainstormRing = document.getElementById('brainstorm-ring');
     8→const micHint       = document.getElementById('mic-hint');
     9→const liveTranscript = document.getElementById('live-transcript');
    10→const liveText      = document.getElementById('live-text');
    11→const transcriptBar = document.getElementById('transcript-bar');
    12→const transcriptText = document.getElementById('transcript-text');
    13→const sendBtn       = document.getElementById('send-btn');
    14→const discardBtn    = document.getElementById('discard-btn');
    15→const transcriptCleanedLabel = document.getElementById('transcript-cleaned-label');
    16→const transcriptRawWrap = document.getElementById('transcript-raw-wrap');
    17→const transcriptRawText = document.getElementById('transcript-raw-text');
    18→const messagesEl    = document.getElementById('messages');
    19→const messagesEmpty = document.getElementById('messages-empty');
    20→const notSupported  = document.getElementById('not-supported');
    21→const settingsBtn   = document.getElementById('settings-btn');
    22→const modalOverlay  = document.getElementById('modal-overlay');
    23→const modalClose    = document.getElementById('modal-close');
    24→const webhookInput  = document.getElementById('webhook-url');
    25→const saveSettings  = document.getElementById('save-settings');
    26→const wakeBtn       = document.getElementById('wake-btn');
    27→
    28→/* ===== State ===== */
    29→let recognition     = null;
    30→let isListening     = false;
    31→let activeMode      = null; // 'quick' | 'brainstorm' | null
    32→let finalTranscript = '';
    33→let interimText     = '';
    34→let silenceTimer    = null;
    35→const SILENCE_DELAY = 3500; // ms — only used in quick mode
    36→
    37→/* ===== Transcript cleaning ===== */
    38→function cleanTranscript(raw) {
    39→  if (!raw) return raw;
    40→
    41→  // Strip obvious spoken filler sounds
    42→  let text = raw.replace(/\b(um+|uh+|er+|hmm+|mhm)\b\s*/gi, ' ');
    43→
    44→  // Collapse multiple whitespace
    45→  text = text.replace(/\s+/g, ' ').trim();
    46→
    47→  // Capitalize first letter
    48→  if (text) {
    49→    text = text.charAt(0).toUpperCase() + text.slice(1);
    50→  }
    51→
    52→  // Capitalize first letter after sentence-ending punctuation
    53→  text = text.replace(/([.!?])\s+([a-z])/g, (_, p, l) => `${p} ${l.toUpperCase()}`);
    54→
    55→  // Add terminal period if absent
    56→  if (text && !/[.!?…]$/.test(text)) {
    57→    text += '.';
    58→  }
    59→
    60→  return text;
    61→}
    62→
    63→/* ===== Brainstorm continuity ===== */
    64→// Chrome stops continuous recognition periodically; we restart seamlessly in brainstorm mode
    65→// and preserve accumulated transcript across restarts.
    66→let brainstormAccumulator  = '';
    67→let _brainstormRestarting  = false;
    68→
    69→/* ===== Wake word state ===== */
    70→let wakeRecognition       = null;
    71→let wakeMode              = false;
    72→let wakeTriggered         = false; // transitioning from wake → main recording
    73→let wakeTriggeredRecording = false; // current recording was initiated by wake word
    74→let wakeRestartTimer      = null;
    75→const WAKE_PHRASES        = ['hey chill', 'hey chil']; // core phrase + common partial
    76→
    77→/* ===== Audio Feedback ===== */
    78→let audioCtx = null;
    79→
    80→function getAudioContext() {
    81→  if (!audioCtx) {
    82→    audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    83→  }
    84→  if (audioCtx.state === 'suspended') {
    85→    audioCtx.resume();
    86→  }
    87→  return audioCtx;
    88→}
    89→
    90→// Prime the AudioContext on first user interaction so it's ready for hands-free sends
    91→function primeAudio() {
    92→  try { getAudioContext(); } catch (_) {}
    93→}
    94→
    95→function _playTone(ctx, frequency, startTime, duration, gain) {
    96→  const osc  = ctx.createOscillator();
    97→  const amp  = ctx.createGain();
    98→  osc.connect(amp);
    99→  amp.connect(ctx.destination);
   100→  osc.type = 'sine';
   101→  osc.frequency.setValueAtTime(frequency, startTime);
   102→  amp.gain.setValueAtTime(0, startTime);
   103→  amp.gain.linearRampToValueAtTime(gain, startTime + 0.01);
   104→  amp.gain.exponentialRampToValueAtTime(0.001, startTime + duration);
   105→  osc.start(startTime);
   106→  osc.stop(startTime + duration);
   107→}
   108→
   109→function playSuccessSound() {
   110→  // Prefer speech synthesis — "Got it" is immediately understood
   111→  if ('speechSynthesis' in window) {
   112→    const utt = new SpeechSynthesisUtterance('Got it');
   113→    utt.rate   = 1.1;
   114→    utt.pitch  = 1.1;
   115→    utt.volume = 1;
   116→    window.speechSynthesis.speak(utt);
   117→    return;
   118→  }
   119→  // Fallback: ascending double chime
   120→  try {
   121→    const ctx = getAudioContext();
   122→    const now = ctx.currentTime;
   123→    _playTone(ctx, 880,  now,        0.22, 0.30); // A5
   124→    _playTone(ctx, 1320, now + 0.18, 0.38, 0.25); // E6
   125→  } catch (e) {
   126→    console.warn('Audio playback failed:', e);
   127→  }
   128→}
   129→
   130→function playFailureSound() {
   131→  // Descending dissonant triple-tone — distinct "uh-oh" signal
   132→  try {
   133→    const ctx = getAudioContext();
   134→    const now = ctx.currentTime;
   135→    _playTone(ctx, 330, now,        0.18, 0.40); // E4
   136→    _playTone(ctx, 262, now + 0.15, 0.18, 0.40); // C4
   137→    _playTone(ctx, 196, now + 0.30, 0.45, 0.35); // G3
   138→  } catch (e) {
   139→    console.warn('Audio playback failed:', e);
   140→  }
   141→}
   142→
   143→/* ===== Service Worker ===== */
   144→if ('serviceWorker' in navigator) {
   145→  navigator.serviceWorker.register('sw.js').catch(() => {/* silent */});
   146→}
   147→
   148→/* ===== Speech Recognition setup ===== */
   149→const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
   150→
   151→if (!SpeechRecognition) {
   152→  notSupported.hidden = false;
   153→  quickBtn.disabled = true;
   154→  quickBtn.setAttribute('aria-disabled', 'true');
   155→  brainstormBtn.disabled = true;
   156→  brainstormBtn.setAttribute('aria-disabled', 'true');
   157→} else {
   158→  initRecognition();
   159→}
   160→
   161→function initRecognition() {
   162→  recognition = new SpeechRecognition();
   163→  recognition.continuous     = true;
   164→  recognition.interimResults = true;
   165→  recognition.lang           = navigator.language || 'en-US';
   166→  recognition.maxAlternatives = 1;
   167→
   168→  recognition.onstart = () => {
   169→    if (_brainstormRestarting) {
   170→      // Seamless brainstorm restart — preserve accumulated transcript, don't reset UI
   171→      isListening = true;
   172→      finalTranscript = brainstormAccumulator;
   173→      interimText = '';
   174→      _brainstormRestarting = false;
   175→      return;
   176→    }
   177→    isListening = true;
   178→    finalTranscript = '';
   179→    brainstormAccumulator = '';
   180→    interimText = '';
   181→    setRecordingUI(true, activeMode);
   182→  };
   183→
   184→  recognition.onresult = (event) => {
   185→    let interim = '';
   186→    for (let i = event.resultIndex; i < event.results.length; i++) {
   187→      const result = event.results[i];
   188→      if (result.isFinal) {
   189→        finalTranscript += result[0].transcript + ' ';
   190→      } else {
   191→        interim += result[0].transcript;
   192→      }
   193→    }
   194→    interimText = interim;
   195→    const displayText = (finalTranscript + interim).trim();
   196→    updateLiveText(displayText);
   197→
   198→    // Silence timer only applies to quick mode
   199→    if (activeMode === 'quick') {
   200→      resetSilenceTimer();
   201→    }
   202→  };
   203→
   204→  recognition.onerror = (event) => {
   205→    // 'no-speech' is common and expected — just stop cleanly
   206→    if (event.error !== 'no-speech') {
   207→      console.warn('Speech recognition error:', event.error);
   208→    }
   209→    _brainstormRestarting = false;
   210→    stopListening();
   211→  };
   212→
   213→  recognition.onend = () => {
   214→    if (isListening && activeMode === 'brainstorm') {
   215→      // Chrome stops continuous recognition periodically — restart seamlessly
   216→      brainstormAccumulator = finalTranscript;
   217→      _brainstormRestarting = true;
   218→      setTimeout(() => {
   219→        if (isListening && activeMode === 'brainstorm') {
   220→          try {
   221→            recognition.start();
   222→          } catch (_) {
   223→            _brainstormRestarting = false;
   224→            brainstormAccumulator = '';
   225→            isListening = false;
   226→            finishRecording();
   227→          }
   228→        } else {
   229→          _brainstormRestarting = false;
   230→        }
   231→      }, 150);
   232→      return;
   233→    }
   234→    // onend fires when recognition stops for any reason
   235→    if (isListening) {
   236→      // We didn't call stop manually yet; auto-stop happened
   237→      finishRecording();
   238→    }
   239→  };
   240→}
   241→
   242→function resetSilenceTimer() {
   243→  clearTimeout(silenceTimer);
   244→  silenceTimer = setTimeout(() => {
   245→    if (isListening) stopListening();
   246→  }, SILENCE_DELAY);
   247→}
   248→
   249→/* ===== Recording controls ===== */
   250→function startListening(mode) {
   251→  if (!recognition || isListening) return;
   252→  activeMode = mode;
   253→  hideTranscriptBar();
   254→
   255→  // Ensure wake recognition is stopped before starting main recording
   256→  if (wakeMode) stopWakeRecognition();
   257→
   258→  try {
   259→    recognition.start();
   260→  } catch (e) {
   261→    console.warn('Could not start recognition:', e);
   262→    // Re-init in case of invalid state
   263→    initRecognition();
   264→    try { recognition.start(); } catch (_) {}
   265→  }
   266→
   267→  if (mode === 'quick') {
   268→    resetSilenceTimer();
   269→  }
   270→}
   271→
   272→function stopListening() {
   273→  clearTimeout(silenceTimer);
   274→  _brainstormRestarting = false; // prevent auto-restart in brainstorm
   275→  isListening = false; // mark before calling stop so onend doesn't re-trigger finishRecording
   276→  if (recognition) {
   277→    try { recognition.stop(); } catch (_) {}
   278→  }
   279→  finishRecording();
   280→}
   281→
   282→function finishRecording() {
   283→  const mode = activeMode;
   284→  setRecordingUI(false, mode);
   285→  const text = finalTranscript.trim();
   286→  brainstormAccumulator = '';
   287→  activeMode = null;
   288→  if (text) {
   289→    if (wakeTriggeredRecording) {
   290→      // Hands-free path: auto-send without requiring a tap
   291→      sendMessage(text);
   292→    } else {
   293→      showTranscriptBar(text, mode);
   294→    }
   295→  }
   296→  wakeTriggeredRecording = false;
   297→  // Resume passive wake word listening if mode is active
   298→  if (wakeMode) scheduleWakeRestart();
   299→  updateWakeHint();
   300→}
   301→
   302→/* ===== UI state helpers ===== */
   303→function setRecordingUI(recording, mode) {
   304→  const quickActive      = recording && mode === 'quick';
   305→  const brainstormActive = recording && mode === 'brainstorm';
   306→
   307→  // Quick button
   308→  quickBtn.classList.toggle('recording', quickActive);
   309→  quickRing.classList.toggle('recording', quickActive);
   310→  quickBtn.setAttribute('aria-pressed', quickActive ? 'true' : 'false');
   311→  quickBtn.setAttribute('aria-label', quickActive ? 'Stop recording' : 'Quick Request – tap to speak');
   312→
   313→  // Brainstorm button
   314→  brainstormBtn.classList.toggle('recording', brainstormActive);
   315→  brainstormRing.classList.toggle('recording', brainstormActive);
   316→  brainstormBtn.setAttribute('aria-pressed', brainstormActive ? 'true' : 'false');
   317→  brainstormBtn.setAttribute('aria-label', brainstormActive ? 'Stop brainstorm recording' : 'Brainstorm – tap for continuous recording');
   318→
   319→  // Shared hint
   320→  if (quickActive) {
   321→    micHint.textContent = 'Listening… tap Quick to stop';
   322→    micHint.classList.add('active');
   323→    micHint.classList.remove('brainstorm-active');
   324→  } else if (brainstormActive) {
   325→    micHint.textContent = 'Recording… tap Brainstorm to stop';
   326→    micHint.classList.add('active', 'brainstorm-active');
   327→  } else {
   328→    micHint.classList.remove('active', 'brainstorm-active');
   329→    updateWakeHint();
   330→  }
   331→
   332→  liveTranscript.hidden = !recording;
   333→  liveTranscript.classList.toggle('brainstorm-mode', recording && mode === 'brainstorm');
   334→  if (!recording) {
   335→    liveText.textContent = 'Listening…';
   336→    liveText.classList.remove('has-text');
   337→  }
   338→}
   339→
   340→function updateLiveText(text) {
   341→  if (text) {
   342→    liveText.textContent = text;
   343→    liveText.classList.add('has-text');
   344→    // Auto-scroll to bottom so latest speech is always visible in brainstorm
   345→    if (activeMode === 'brainstorm') {
   346→      liveTranscript.scrollTop = liveTranscript.scrollHeight;
   347→    }
   348→  } else {
   349→    liveText.textContent = 'Listening…';
   350→    liveText.classList.remove('has-text');
   351→  }
   352→}
   353→
   354→function showTranscriptBar(text, mode) {
   355→  if (mode === 'brainstorm') {
   356→    const cleaned = cleanTranscript(text);
   357→    transcriptText.textContent = cleaned;
   358→    transcriptRawText.textContent = text;
   359→    transcriptCleanedLabel.hidden = false;
   360→    transcriptRawWrap.hidden = false;
   361→  } else {
   362→    transcriptText.textContent = text;
   363→    transcriptCleanedLabel.hidden = true;
   364→    transcriptRawWrap.hidden = true;
   365→  }
   366→  transcriptBar.hidden = false;
   367→}
   368→
   369→function hideTranscriptBar() {
   370→  transcriptBar.hidden = true;
   371→  transcriptText.textContent = '';
   372→  transcriptRawText.textContent = '';
   373→  transcriptCleanedLabel.hidden = true;
   374→  transcriptRawWrap.hidden = true;
   375→}
   376→
   377→/* ===== Button click handlers ===== */
   378→quickBtn.addEventListener('click', () => {
   379→  primeAudio();
   380→  if (isListening && activeMode === 'quick') {
   381→    stopListening();
   382→  } else if (!isListening) {
   383→    wakeTriggeredRecording = false; // manual tap — show transcript bar after
   384→    startListening('quick');
   385→  }
   386→});
   387→
   388→brainstormBtn.addEventListener('click', () => {
   389→  primeAudio();
   390→  if (isListening && activeMode === 'brainstorm') {
   391→    stopListening();
   392→  } else if (!isListening) {
   393→    wakeTriggeredRecording = false;
   394→    startListening('brainstorm');
   395→  }
   396→});
   397→
   398→/* ===== Send / Discard ===== */
   399→sendBtn.addEventListener('click', async () => {
   400→  primeAudio();
   401→  const text = transcriptText.textContent.trim();
   402→  if (!text) return;
   403→  hideTranscriptBar();
   404→  await sendMessage(text);
   405→});
   406→
   407→discardBtn.addEventListener('click', () => {
   408→  hideTranscriptBar();
   409→});
   410→
   411→/* ===== Webhook send ===== */
   412→async function sendMessage(text) {
   413→  const webhookUrl = localStorage.getItem('webhookUrl') || '';
   414→  const timestamp  = new Date().toISOString();
   415→  const payload    = { text, source: 'hey-chill', timestamp };
   416→
   417→  // Add message to history immediately
   418→  const msgEl = addMessage(text, timestamp, 'sending');
   419→
   420→  if (!webhookUrl) {
   421→    updateMessageStatus(msgEl, 'no-webhook');
   422→    return;
   423→  }
   424→
   425→  try {
   426→    const res = await fetch(webhookUrl, {
   427→      method: 'POST',
   428→      headers: { 'Content-Type': 'application/json' },
   429→      body: JSON.stringify(payload),
   430→    });
   431→    if (!res.ok) throw new Error(`HTTP ${res.status}`);
   432→    updateMessageStatus(msgEl, 'sent');
   433→    playSuccessSound();
   434→  } catch (err) {
   435→    console.warn('Webhook error:', err);
   436→    updateMessageStatus(msgEl, 'error');
   437→    playFailureSound();
   438→  }
   439→}
   440→
   441→/* ===== Message history ===== */
   442→function addMessage(text, timestamp, status) {
   443→  // Hide empty state
   444→  messagesEmpty.style.display = 'none';
   445→
   446→  const el = document.createElement('div');
   447→  el.className = `message ${status}`;
   448→
   449→  const timeStr = new Date(timestamp).toLocaleTimeString([], {
   450→    hour: '2-digit',
   451→    minute: '2-digit',
   452→  });
   453→
   454→  const statusLabel = {
   455→    sending:    'Sending…',
   456→    sent:       'Sent',
   457→    error:      'Failed',
   458→    'no-webhook': 'No webhook',
   459→  };
   460→
   461→  el.innerHTML = `
   462→    <p class="message-text">${escapeHtml(text)}</p>
   463→    <div class="message-meta">
   464→      <span class="message-time">${timeStr}</span>
   465→      <span class="message-status">${statusLabel[status] || status}</span>
   466→    </div>
   467→  `;
   468→
   469→  messagesEl.appendChild(el);
   470→  el.scrollIntoView({ behavior: 'smooth', block: 'end' });
   471→  return el;
   472→}
   473→
   474→function updateMessageStatus(el, status) {
   475→  el.className = `message ${status}`;
   476→  const statusEl = el.querySelector('.message-status');
   477→  const labels = {
   478→    sent:         'Sent',
   479→    error:        'Failed',
   480→    'no-webhook': 'No webhook set',
   481→  };
   482→  if (statusEl) statusEl.textContent = labels[status] || status;
   483→}
   484→
   485→function escapeHtml(str) {
   486→  return str
   487→    .replace(/&/g, '&amp;')
   488→    .replace(/</g, '&lt;')
   489→    .replace(/>/g, '&gt;')
   490→    .replace(/"/g, '&quot;')
   491→    .replace(/'/g, '&#39;');
   492→}
   493→
   494→/* ===== Settings modal ===== */
   495→settingsBtn.addEventListener('click', openSettings);
   496→modalClose.addEventListener('click',  closeSettings);
   497→modalOverlay.addEventListener('click', (e) => {
   498→  if (e.target === modalOverlay) closeSettings();
   499→});
   500→
   501→document.addEventListener('keydown', (e) => {
   502→  if (e.key === 'Escape') closeSettings();
   503→});
   504→
   505→saveSettings.addEventListener('click', () => {
   506→  const url = webhookInput.value.trim();
   507→  localStorage.setItem('webhookUrl', url);
   508→  closeSettings();
   509→});
   510→
   511→function openSettings() {
   512→  webhookInput.value = localStorage.getItem('webhookUrl') || '';
   513→  modalOverlay.hidden = false;
   514→  webhookInput.focus();
   515→}
   516→
   517→function closeSettings() {
   518→  modalOverlay.hidden = true;
   519→}
   520→
   521→/* ===== Wake Word Detection ===== */
   522→
   523→function isWakePhrase(transcript) {
   524→  return WAKE_PHRASES.some(phrase => transcript.includes(phrase));
   525→}
   526→
   527→function initWakeRecognition() {
   528→  wakeRecognition = new SpeechRecognition();
   529→  wakeRecognition.continuous     = true;
   530→  wakeRecognition.interimResults = true;
   531→  wakeRecognition.lang           = navigator.language || 'en-US';
   532→  wakeRecognition.maxAlternatives = 1;
   533→
   534→  wakeRecognition.onresult = (event) => {
   535→    for (let i = event.resultIndex; i < event.results.length; i++) {
   536→      const transcript = event.results[i][0].transcript.toLowerCase().trim();
   537→      if (isWakePhrase(transcript)) {
   538→        handleWakeWordDetected();
   539→        return;
   540→      }
   541→    }
   542→  };
   543→
   544→  wakeRecognition.onerror = (event) => {
   545→    if (event.error === 'not-allowed' || event.error === 'service-not-allowed') {
   546→      // Microphone access denied — silently disable wake mode
   547→      disableWakeMode();
   548→      return;
   549→    }
   550→    if (wakeMode && !isListening && !wakeTriggered) {
   551→      scheduleWakeRestart();
   552→    }
   553→  };
   554→
   555→  wakeRecognition.onend = () => {
   556→    // Chrome stops continuous recognition periodically — restart unless we
   557→    // deliberately stopped it to hand off to main recording.
   558→    if (wakeMode && !isListening && !wakeTriggered) {
   559→      scheduleWakeRestart();
   560→    }
   561→  };
   562→}
   563→
   564→function startWakeRecognition() {
   565→  if (!wakeRecognition) initWakeRecognition();
   566→  wakeTriggered = false;
   567→  quickRing.classList.add('listening-passive'); // passive glow on quick button only
   568→  try {
   569→    wakeRecognition.start();
   570→  } catch (e) {
   571→    // InvalidStateError when already started — reinit and retry
   572→    initWakeRecognition();
   573→    try { wakeRecognition.start(); } catch (_) {}
   574→  }
   575→}
   576→
   577→function stopWakeRecognition() {
   578→  quickRing.classList.remove('listening-passive');
   579→  if (wakeRecognition) {
   580→    try { wakeRecognition.stop(); } catch (_) {}
   581→  }
   582→}
   583→
   584→function scheduleWakeRestart() {
   585→  clearTimeout(wakeRestartTimer);
   586→  wakeRestartTimer = setTimeout(() => {
   587→    if (wakeMode && !isListening && !wakeTriggered) {
   588→      startWakeRecognition();
   589→    }
   590→  }, 300);
   591→}
   592→
   593→function handleWakeWordDetected() {
   594→  if (isListening || wakeTriggered) return;
   595→  wakeTriggered = true;
   596→  wakeTriggeredRecording = true; // flag so finishRecording auto-sends
   597→  stopWakeRecognition();
   598→  // Give the recognition engine a moment to fully stop before starting main recording
   599→  setTimeout(() => {
   600→    wakeTriggered = false;
   601→    startListening('quick'); // wake word always triggers quick mode
   602→  }, 250);
   603→}
   604→
   605→function enableWakeMode() {
   606→  wakeMode = true;
   607→  wakeBtn.classList.add('wake-active');
   608→  wakeBtn.setAttribute('aria-pressed', 'true');
   609→  wakeBtn.setAttribute('aria-label', 'Disable wake word');
   610→  wakeBtn.title = 'Wake word: ON';
   611→  localStorage.setItem('wakeMode', '1');
   612→  updateWakeHint();
   613→  if (!isListening) startWakeRecognition();
   614→}
   615→
   616→function disableWakeMode() {
   617→  wakeMode = false;
