    96→  transition: background var(--transition), color var(--transition);
    97→}
    98→
    99→.icon-btn svg {
   100→  width: 18px;
   101→  height: 18px;
   102→}
   103→
   104→.icon-btn:hover, .icon-btn:focus-visible {
   105→  background: var(--surface-hover);
   106→  color: var(--text);
   107→  outline: none;
   108→}
   109→
   110→/* ===== Messages ===== */
   111→.messages {
   112→  flex: 1;
   113→  overflow-y: auto;
   114→  padding: 12px 20px;
   115→  display: flex;
   116→  flex-direction: column;
   117→  gap: 10px;
   118→  -webkit-overflow-scrolling: touch;
   119→  scrollbar-width: thin;
   120→  scrollbar-color: var(--border) transparent;
   121→}
   122→
   123→.messages::-webkit-scrollbar {
   124→  width: 4px;
   125→}
   126→
   127→.messages::-webkit-scrollbar-track {
   128→  background: transparent;
   129→}
   130→
   131→.messages::-webkit-scrollbar-thumb {
   132→  background: var(--border);
   133→  border-radius: 2px;
   134→}
   135→
   136→.messages-empty {
   137→  flex: 1;
   138→  display: flex;
   139→  align-items: center;
   140→  justify-content: center;
   141→}
   142→
   143→.messages-empty p {
   144→  color: var(--text-muted);
   145→  font-size: 0.9rem;
   146→  text-align: center;
   147→}
   148→
   149→/* Message bubble */
   150→.message {
   151→  background: var(--surface);
   152→  border: 1px solid var(--border);
   153→  border-radius: var(--radius);
   154→  border-bottom-right-radius: 4px;
   155→  padding: 12px 16px;
   156→  max-width: 100%;
   157→  word-break: break-word;
   158→  animation: slide-up 0.25s ease both;
   159→}
   160→
   161→.message.sending {
   162→  opacity: 0.6;
   163→}
   164→
   165→.message.sent {
   166→  border-color: rgba(233, 69, 96, 0.2);
   167→}
   168→
   169→.message.error {
   170→  border-color: rgba(255, 80, 80, 0.3);
   171→}
   172→
   173→.message-text {
   174→  font-size: 0.95rem;
   175→  line-height: 1.5;
   176→  color: var(--text);
   177→}
   178→
   179→.message-meta {
   180→  display: flex;
   181→  align-items: center;
   182→  gap: 8px;
   183→  margin-top: 6px;
   184→}
   185→
   186→.message-time {
   187→  font-size: 0.75rem;
   188→  color: var(--text-muted);
   189→}
   190→
   191→.message-status {
   192→  font-size: 0.72rem;
   193→  padding: 2px 7px;
   194→  border-radius: 20px;
   195→  background: var(--surface);
   196→  color: var(--text-muted);
   197→}
   198→
   199→.message.sent .message-status {
   200→  background: rgba(233, 69, 96, 0.15);
   201→  color: var(--accent);
   202→}
   203→
   204→.message.error .message-status {
   205→  background: rgba(255, 80, 80, 0.15);
   206→  color: #ff6b6b;
   207→}
   208→
   209→@keyframes slide-up {
   210→  from { opacity: 0; transform: translateY(12px); }
   211→  to   { opacity: 1; transform: translateY(0); }
   212→}
   213→
   214→/* ===== Live Transcript ===== */
   215→.live-transcript {
   216→  margin: 0 20px 8px;
   217→  background: var(--surface);
   218→  border: 1px solid var(--border);
   219→  border-radius: var(--radius);
   220→  padding: 14px 16px;
   221→  animation: fade-in 0.2s ease;
   222→}
   223→
   224→.live-transcript p {
   225→  font-size: 0.92rem;
   226→  color: var(--text-muted);
   227→  font-style: italic;
   228→  line-height: 1.5;
   229→  min-height: 1.4em;
   230→}
   231→
   232→.live-transcript p.has-text {
   233→  color: var(--text);
   234→  font-style: normal;
   235→}
   236→
   237→/* ===== Transcript Bar (post-recording) ===== */
   238→.transcript-bar {
   239→  margin: 0 20px 12px;
   240→  background: var(--bg-2);
   241→  border: 1px solid var(--border);
   242→  border-radius: var(--radius);
   243→  padding: 16px;
   244→  animation: slide-up 0.2s ease;
   245→}
   246→
   247→.transcript-text {
   248→  font-size: 0.95rem;
   249→  line-height: 1.5;
   250→  color: var(--text);
   251→  margin-bottom: 14px;
   252→  word-break: break-word;
   253→}
   254→
   255→.transcript-actions {
   256→  display: flex;
   257→  gap: 10px;
   258→  justify-content: flex-end;
   259→}
   260→
   261→/* ===== Buttons ===== */
   262→.btn-ghost {
   263→  background: transparent;
   264→  border: 1px solid var(--border);
   265→  color: var(--text-muted);
   266→  border-radius: var(--radius-sm);
   267→  padding: 8px 18px;
   268→  font-size: 0.9rem;
   269→  cursor: pointer;
   270→  transition: all var(--transition);
   271→}
   272→
   273→.btn-ghost:hover, .btn-ghost:focus-visible {
   274→  background: var(--surface);
   275→  color: var(--text);
   276→  outline: none;
   277→}
   278→
   279→.btn-send {
   280→  background: var(--accent);
   281→  border: none;
   282→  color: #fff;
   283→  border-radius: var(--radius-sm);
   284→  padding: 8px 22px;
   285→  font-size: 0.9rem;
   286→  font-weight: 600;
   287→  cursor: pointer;
   288→  transition: all var(--transition);
   289→  box-shadow: 0 2px 12px rgba(233, 69, 96, 0.35);
   290→}
   291→
   292→.btn-send:hover, .btn-send:focus-visible {
   293→  background: #ff5c75;
   294→  outline: none;
   295→  box-shadow: 0 4px 20px rgba(233, 69, 96, 0.55);
   296→}
   297→
   298→/* ===== Mic Section ===== */
   299→.mic-section {
   300→  flex-shrink: 0;
   301→  display: flex;
   302→  flex-direction: column;
   303→  align-items: center;
   304→  padding: 16px 20px 36px;
   305→  gap: 16px;
   306→}
   307→
   308→.mic-hint {
   309→  font-size: 0.85rem;
   310→  color: var(--text-muted);
   311→  letter-spacing: 0.04em;
   312→  transition: color var(--transition);
   313→  min-height: 1.2em;
   314→}
   315→
   316→.mic-hint.active {
   317→  color: var(--accent);
   318→}
   319→
   320→/* Dual-mode button container */
   321→.mic-buttons {
   322→  display: flex;
   323→  align-items: flex-start;
   324→  justify-content: center;
   325→  gap: 28px;
   326→}
   327→
   328→.mode-btn-wrap {
   329→  display: flex;
   330→  flex-direction: column;
   331→  align-items: center;
   332→  gap: 10px;
   333→}
   334→
   335→.mode-label {
   336→  font-size: 0.72rem;
   337→  font-weight: 700;
   338→  letter-spacing: 0.08em;
   339→  text-transform: uppercase;
   340→  color: var(--text-muted);
   341→  transition: color var(--transition);
   342→}
   343→
   344→.mode-label.brainstorm-label {
   345→  color: rgba(163, 121, 221, 0.7);
   346→}
   347→
   348→/* Shrink buttons slightly for side-by-side layout */
   349→.mic-buttons .mic-ring {
   350→  width: 112px;
   351→  height: 112px;
   352→}
   353→
   354→.mic-buttons .mic-btn {
   355→  width: 76px;
   356→  height: 76px;
   357→}
   358→
   359→.mic-buttons .mic-icon {
   360→  width: 30px;
   361→  height: 30px;
   362→}
   363→
   364→/* Ring / glow around button */
   365→.mic-ring {
   366→  position: relative;
   367→  width: var(--ring-size);
   368→  height: var(--ring-size);
   369→  display: flex;
   370→  align-items: center;
   371→  justify-content: center;
   372→}
   373→
   374→.mic-ring::before,
   375→.mic-ring::after {
   376→  content: '';
   377→  position: absolute;
   378→  inset: 0;
   379→  border-radius: 50%;
   380→  border: 2px solid transparent;
   381→  transition: all 0.3s ease;
   382→}
   383→
   384→.mic-ring.recording::before {
   385→  border-color: var(--accent-glow);
   386→  animation: ring-pulse 1.4s ease-in-out infinite;
   387→}
   388→
   389→.mic-ring.recording::after {
   390→  border-color: rgba(233, 69, 96, 0.15);
   391→  animation: ring-pulse 1.4s ease-in-out 0.7s infinite;
   392→}
   393→
   394→@keyframes ring-pulse {
   395→  0%   { transform: scale(1); opacity: 1; }
   396→  100% { transform: scale(1.6); opacity: 0; }
   397→}
   398→
   399→/* The mic button */
   400→.mic-btn {
   401→  position: relative;
   402→  width: var(--mic-size);
   403→  height: var(--mic-size);
   404→  border-radius: 50%;
   405→  border: none;
   406→  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
   407→  color: #fff;
   408→  cursor: pointer;
   409→  display: flex;
   410→  align-items: center;
   411→  justify-content: center;
   412→  box-shadow:
   413→    0 4px 24px rgba(0, 0, 0, 0.4),
   414→    0 0 0 1px rgba(255, 255, 255, 0.08);
   415→  transition: transform 0.15s ease, box-shadow 0.15s ease;
   416→  -webkit-user-select: none;
   417→  user-select: none;
   418→  touch-action: manipulation;
   419→  z-index: 1;
   420→}
   421→
   422→.mic-btn:hover {
   423→  transform: scale(1.05);
   424→  box-shadow:
   425→    0 6px 32px rgba(0, 0, 0, 0.5),
   426→    0 0 0 1px rgba(255, 255, 255, 0.12);
   427→}
   428→
   429→.mic-btn:active {
   430→  transform: scale(0.96);
   431→}
   432→
   433→.mic-btn:focus-visible {
   434→  outline: 2px solid var(--accent);
   435→  outline-offset: 4px;
   436→}
   437→
   438→.mic-btn.recording {
   439→  background: linear-gradient(145deg, var(--accent), #c0392b);
   440→  box-shadow:
   441→    0 4px 32px var(--accent-glow),
   442→    0 0 0 1px rgba(233, 69, 96, 0.3);
   443→  animation: mic-glow 1.4s ease-in-out infinite alternate;
   444→}
   445→
   446→@keyframes mic-glow {
   447→  from { box-shadow: 0 4px 24px var(--accent-glow), 0 0 0 1px rgba(233, 69, 96, 0.3); }
   448→  to   { box-shadow: 0 4px 48px rgba(233, 69, 96, 0.7), 0 0 0 1px rgba(233, 69, 96, 0.5); }
   449→}
   450→
   451→.mic-icon {
   452→  width: 36px;
   453→  height: 36px;
   454→  transition: transform var(--transition);
   455→}
   456→
   457→.mic-btn.recording .mic-icon {
   458→  transform: scale(1.1);
   459→}
   460→
   461→/* ===== Brainstorm button colour overrides ===== */
   462→.mic-btn.brainstorm-btn {
   463→  background: linear-gradient(145deg, var(--bg-3), var(--accent-2));
   464→}
   465→
   466→.mic-btn.brainstorm-btn:hover {
   467→  transform: scale(1.05);
   468→}
   469→
   470→.mic-btn.brainstorm-btn.recording {
   471→  background: linear-gradient(145deg, var(--accent-2), #7b2fbe);
   472→  box-shadow:
   473→    0 4px 32px rgba(83, 52, 131, 0.55),
   474→    0 0 0 1px rgba(163, 121, 221, 0.35);
   475→  animation: brainstorm-glow 1.4s ease-in-out infinite alternate;
   476→}
   477→
   478→@keyframes brainstorm-glow {
   479→  from { box-shadow: 0 4px 24px rgba(83, 52, 131, 0.4),  0 0 0 1px rgba(163, 121, 221, 0.3); }
   480→  to   { box-shadow: 0 4px 48px rgba(83, 52, 131, 0.75), 0 0 0 1px rgba(163, 121, 221, 0.55); }
   481→}
   482→
   483→/* Brainstorm ring pulses in purple when recording */
   484→.mic-ring.brainstorm-ring.recording::before {
   485→  border-color: rgba(163, 121, 221, 0.55);
   486→}
   487→
   488→.mic-ring.brainstorm-ring.recording::after {
   489→  border-color: rgba(163, 121, 221, 0.2);
   490→}
   491→
   492→/* Active mode label colours */
   493→.mic-hint.active.brainstorm-active {
   494→  color: rgba(163, 121, 221, 1);
   495→}
   496→
   497→/* ===== Not supported ===== */
   498→.not-supported {
   499→  margin: 0 20px 20px;
   500→  background: rgba(255, 80, 80, 0.1);
   501→  border: 1px solid rgba(255, 80, 80, 0.25);
   502→  border-radius: var(--radius);
   503→  padding: 14px 16px;
   504→  text-align: center;
   505→  font-size: 0.9rem;
   506→  color: #ff9999;
   507→}
   508→
   509→/* ===== Modal ===== */
   510→.modal-overlay {
   511→  position: fixed;
   512→  inset: 0;
   513→  background: rgba(0, 0, 0, 0.65);
   514→  backdrop-filter: blur(4px);
   515→  -webkit-backdrop-filter: blur(4px);
   516→  display: flex;
   517→  align-items: flex-end;
   518→  justify-content: center;
   519→  z-index: 100;
   520→  animation: fade-in 0.2s ease;
   521→}
   522→
   523→.modal-overlay[hidden] {
   524→  display: none;
   525→}
   526→
   527→.modal {
   528→  background: var(--bg-2);
   529→  border: 1px solid var(--border);
   530→  border-radius: var(--radius) var(--radius) 0 0;
   531→  width: 100%;
   532→  max-width: 480px;
   533→  padding: 0;
   534→  animation: slide-modal 0.3s cubic-bezier(0.4, 0, 0.2, 1);
   535→}
   536→
   537→@media (min-height: 600px) {
   538→  .modal-overlay {
   539→    align-items: center;
   540→  }
   541→  .modal {
   542→    border-radius: var(--radius);
   543→    max-width: 420px;
   544→  }
   545→}
   546→
   547→@keyframes slide-modal {
   548→  from { transform: translateY(40px); opacity: 0; }
   549→  to   { transform: translateY(0); opacity: 1; }
   550→}
   551→
   552→.modal-header {
   553→  display: flex;
   554→  align-items: center;
   555→  justify-content: space-between;
   556→  padding: 20px 20px 16px;
   557→  border-bottom: 1px solid var(--border);
   558→}
   559→
   560→.modal-header h2 {
   561→  font-size: 1.1rem;
   562→  font-weight: 600;
   563→}
   564→
   565→.modal-body {
   566→  padding: 20px;
   567→  display: flex;
   568→  flex-direction: column;
   569→  gap: 8px;
   570→}
   571→
   572→.modal-body label {
   573→  font-size: 0.85rem;
   574→  color: var(--text-muted);
   575→  font-weight: 500;
   576→}
   577→
   578→.modal-body input {
   579→  background: var(--surface);
   580→  border: 1px solid var(--border);
   581→  border-radius: var(--radius-sm);
   582→  color: var(--text);
   583→  font-size: 0.95rem;
   584→  padding: 12px 14px;
   585→  width: 100%;
   586→  transition: border-color var(--transition);
   587→  font-family: inherit;
   588→}
   589→
   590→.modal-body input::placeholder {
   591→  color: var(--text-muted);
   592→}
   593→
   594→.modal-body input:focus {
   595→  outline: none;
   596→  border-color: var(--accent);
   597→  box-shadow: 0 0 0 2px rgba(233, 69, 96, 0.15);
   598→}
   599→
   600→.field-hint {
   601→  font-size: 0.78rem;
   602→  color: var(--text-muted);
   603→}
   604→
   605→.modal-footer {
   606→  padding: 16px 20px 24px;
   607→  display: flex;
   608→  justify-content: flex-end;
   609→}
   610→
   611→/* ===== Header actions ===== */
   612→.header-actions {
   613→  display: flex;
   614→  align-items: center;
   615→  gap: 8px;
   616→}
   617→
   618→/* ===== Passive listening state (wake mode on, waiting for wake word) ===== */
   619→.mic-ring.listening-passive::before {
   620→  border-color: rgba(83, 52, 131, 0.5);
   621→  animation: ring-breathe 2.8s ease-in-out infinite;
   622→}
   623→
   624→.mic-ring.listening-passive::after {
   625→  border-color: rgba(83, 52, 131, 0.2);
   626→  animation: ring-breathe 2.8s ease-in-out 1.4s infinite;
   627→}
   628→
   629→.mic-ring.listening-passive .mic-btn {
   630→  animation: passive-glow 2.8s ease-in-out infinite alternate;
   631→}
   632→
   633→@keyframes ring-breathe {
   634→  0%, 100% { transform: scale(1);    opacity: 0.7; }
   635→  50%       { transform: scale(1.4); opacity: 0; }
   636→}
   637→
   638→@keyframes passive-glow {
   639→  from { box-shadow: 0 4px 24px rgba(0, 0, 0, 0.4), 0 0 0 1px rgba(83, 52, 131, 0.15); }
   640→  to   { box-shadow: 0 4px 32px rgba(83, 52, 131, 0.25), 0 0 0 3px rgba(83, 52, 131, 0.35); }
   641→}
   642→
   643→/* Wake word button active state */
   644→.icon-btn.wake-active {
   645→  color: var(--accent);
   646→  background: rgba(233, 69, 96, 0.12);
   647→  border-color: rgba(233, 69, 96, 0.3);
   648→  animation: wake-btn-pulse 2.5s ease-in-out infinite;
   649→}
   650→
   651→@keyframes wake-btn-pulse {
   652→  0%, 100% { box-shadow: 0 0 0 0 rgba(233, 69, 96, 0); }
   653→  50%       { box-shadow: 0 0 0 4px rgba(233, 69, 96, 0.15); }
   654→}
   655→
   656→/* ===== Brainstorm dual-transcript ===== */
   657→.transcript-section-label {
   658→  display: block;
   659→  font-size: 0.72rem;
   660→  font-weight: 700;
   661→  letter-spacing: 0.08em;
   662→  text-transform: uppercase;
   663→  color: rgba(163, 121, 221, 0.85);
   664→  margin-bottom: 6px;
   665→}
   666→
   667→.transcript-section-label--raw {
   668→  color: var(--text-muted);
   669→}
   670→
   671→.transcript-raw-wrap {
   672→  margin-top: 14px;
   673→  padding-top: 12px;
   674→  border-top: 1px solid var(--border);
   675→}
   676→
   677→.transcript-raw-text {
   678→  font-size: 0.85rem;
   679→  line-height: 1.5;
   680→  color: var(--text-muted);
   681→  word-break: break-word;
   682→}
   683→
   684→/* Live transcript: auto-scroll container in brainstorm mode */
   685→.live-transcript.brainstorm-mode {
   686→  max-height: 130px;
   687→  overflow-y: auto;
   688→  scroll-behavior: smooth;
   689→}
   690→
   691→/* ===== Utilities ===== */
   692→@keyframes fade-in {
   693→  from { opacity: 0; }
   694→  to   { opacity: 1; }
   695→}
   696→
   697→/* Safe area for notch phones */
   698→@supports (padding-bottom: env(safe-area-inset-bottom)) {
   699→  .mic-section {
   700→    padding-bottom: calc(36px + env(safe-area-inset-bottom));
   701→  }
   702→}
   703→

